// src/components/payment/Payment.jsx
import { useState, useEffect } from "react";
import './Payment.css';

const AmountForm = ({ amount = 0, transportData, onSuccess, onError }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    if (amount) {
      // Check if amount exceeds limit
      if (amount > 50000) {
        setError(`Amount ₹${amount.toLocaleString('en-IN')} exceeds maximum limit of ₹50,000. Please use Cash on Delivery or contact support.`);
        if (onError) onError("Amount exceeds limit");
      } else if (amount >= 10) {
        handleSubmit(amount);
      }
    }
  }, [amount]);

  const handleSubmit = async (submitAmount) => {
    if (!submitAmount || submitAmount < 10 || submitAmount > 50000) {
      setError(`Amount must be between ₹10 and ₹50,000. Current amount: ₹${submitAmount?.toLocaleString('en-IN')}`);
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      const token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJfaWQiOiI2NzEwODhmZjM4ZGJhNzhhZDY2YjVmZWIiLCJwaG9uZU51bWJlciI6ODgxMDMwMDcyNCwiZW1haWwiOiJzeTI0MTUyN0BnbWFpbC5jb20iLCJyb2xlIjoiY2hhZ2Fuc0VtcGxveWVlMiIsImxvZ2luSWQiOiJmOGUzOWRhOC03MmQ2LTRmNTUtYWJlMC0xM2Q5YWIxMjJmZTkiLCJpYXQiOjE3NjkxNDM0NDUsImV4cCI6MTc3NjkxOTQ0NX0.Y8_yAqXxKhw7Hijfn5zJkHfWDHqijjRyxDom2XwqzFs";
      
      if (!token) {
        setError("Authentication required. Please login.");
        setIsLoading(false);
        return;
      }

      // Convert amount to paise (multiply by 100) for payment gateway
      const amountInPaise = Math.round(submitAmount * 100);

      console.log("Sending payment request:", {
        amount: amountInPaise,
        originalAmount: submitAmount
      });

      const response = await fetch(
        `https://chagans.com/payment/addMoneyTen`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json"
          },
          body: JSON.stringify({
            amount: amountInPaise,
            transportData: {
              ...transportData,
              trackingId: `TRK${Math.floor(100000 + Math.random() * 900000)}`,
            },
            mobile: "7983920962",
            apiType: "API",
          }),
        }
      );

      const data = await response.json();
      console.log("Payment response:", data);
      
      if (data.success) {
        // Create form and submit to payment gateway
        const form = document.createElement('form');
        form.method = 'POST';
        form.action = data.data.APIURL;
        form.target = '_blank';
        
        Object.entries(data.data).forEach(([key, value]) => {
          if (key !== 'APIURL' && value) {
            const input = document.createElement('input');
            input.type = 'hidden';
            input.name = key.toUpperCase();
            input.value = value;
            form.appendChild(input);
          }
        });
        
        document.body.appendChild(form);
        form.submit();
        document.body.removeChild(form);
        
        if (onSuccess) {
          onSuccess("Redirecting to payment gateway...");
        }
      } else {
        setError(data.message || "Payment failed. Please try again.");
        if (onError) onError(data.message);
      }
    } catch (err) {
      console.error('Payment error:', err);
      setError("Network error. Please check your connection.");
      if (onError) onError("Network error");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="amount-form-container">
      {/* Loading State */}
      {isLoading && (
        <div className="loading-indicator">
          <div className="spinner"></div>
          <div>
            <p style={{margin: '0 0 5px 0', fontWeight: '500'}}>Redirecting to payment gateway...</p>
            <p style={{margin: '0', fontSize: '12px', color: '#666'}}>Please do not close this window</p>
          </div>
        </div>
      )}

      {/* Error Message */}
      {error && (
        <div className="error-message">
          <div style={{flex: 1}}>
            <strong style={{color: '#dc2626'}}>⚠️ Error: </strong>
            {error}
          </div>
          <button 
            onClick={() => {
              setError("");
              if (onError) onError();
            }}
            style={{
              padding: '8px 16px',
              background: '#6b7280',
              color: 'white',
              border: 'none',
              borderRadius: '6px',
              cursor: 'pointer',
              fontSize: '14px'
            }}
          >
            Use COD Instead
          </button>
        </div>
      )}

      {/* Initial Message */}
      {!isLoading && !error && amount < 150000 && (
        <div className="info-message">
          <p>⚡ Initializing secure payment for ₹{amount.toLocaleString('en-IN')}...</p>
        </div>
      )}
    </div>
  );
};

export default AmountForm;
